            graph.insertVertex(parent, null, '\uD83D\uDD23 Step 2: Score each principle 1\u20135 in the scorecard', pt.x + PAD + stepW + 8, stepY, stepW, 32, stepStyle + 'fillColor=#DBEAFE;strokeColor=#3B82F6;');
