    FrameworkCatalog.register('geMckinsey', 'GE–McKinsey Nine-Box Matrix', 'Enterprise & Org Design', function (pt, parent) {
        model.beginUpdate();
        try {
            matrix3x3(parent, {
                pt: pt, key: 'geMckinsey', title: 'GE–McKinsey Nine-Box Matrix', titleIcon: '🔲', rootFill: '#0E7490', rootStroke: '#0891B2',
                yAxis: { label: 'Industry Attractiveness', desc: 'How attractive the market is (size, growth, margin, risk). Plot higher for more attractive industries.' },
                xAxis: { label: 'Competitive Strength', desc: 'How strong your position is (share, brand, cost, capability). Plot further right for greater strength.' },
                cells: [
                    [
                        { name: '🟡 High Attr / Low Str', body: 'Selective — buy, ally or niche down.', fill: '#FEFCE8', stroke: '#CA8A04', text: '#854D0E', desc: 'Attractive market but weak position — invest selectively, or acquire strength. Source: attractiveness × strength scores.' },
                        { name: '🟢 High Attr / Mid Str', body: 'Invest / grow — build the lead.', fill: '#ECFDF5', stroke: '#22C55E', text: '#166534', desc: 'Attractive market, decent position — invest to grow share. Source: attractiveness × strength scores.' },
                        { name: '🟢 High Attr / High Str', body: 'Invest / grow — double down.', fill: '#DCFCE7', stroke: '#16A34A', text: '#166534', desc: 'Top-right: attractive market and strong position — double down. Source: attractiveness × strength scores.' }
                    ],
                    [
                        { name: '🔴 Mid Attr / Low Str', body: 'Harvest / exit.', fill: '#FFF7ED', stroke: '#F97316', text: '#9A3412', desc: 'Middling market, weak position — harvest or exit. Source: attractiveness × strength scores.' },
                        { name: '🟡 Mid / Mid', body: 'Selectivity — focus the wins.', fill: '#FEFCE8', stroke: '#CA8A04', text: '#854D0E', desc: 'Middle of both axes — invest only where you can win. Source: attractiveness × strength scores.' },
                        { name: '🟢 Mid / High Str', body: 'Invest / grow.', fill: '#ECFDF5', stroke: '#22C55E', text: '#166534', desc: 'Strong position in a middling market — grow selectively. Source: attractiveness × strength scores.' }
                    ],
                    [
                        { name: '🔴 Low / Low', body: 'Harvest / exit.', fill: '#FEF2F2', stroke: '#EF4444', text: '#991B1B', desc: 'Bottom-left: unattractive market, weak position — harvest cash or divest. Source: attractiveness × strength scores.' },
                        { name: '🔴 Low / Mid', body: 'Harvest / exit.', fill: '#FEF2F2', stroke: '#EF4444', text: '#991B1B', desc: 'Weak market, moderate position — harvest or reposition. Source: attractiveness × strength scores.' },
                        { name: '🟡 Low / High Str', body: 'Selective — milk the strength.', fill: '#FEFCE8', stroke: '#CA8A04', text: '#854D0E', desc: 'Weak market but strong position — harvest the cash, defend the lead. Source: attractiveness × strength scores.' }
                    ]
                ],
                footer: '🔲 Plot each business unit by Industry Attractiveness (Y) × Competitive Strength (X). Green = invest/grow, amber = selectivity, red = harvest/exit. Type into any cell — all editable.'
            });
        } finally { model.endUpdate(); }
    });

