    FrameworkCatalog.register('goffeeJones', 'Goffee & Jones Culture Framework', 'Enterprise & Org Design', function (pt, parent) {
        model.beginUpdate();
        try {
            quadrant(parent, {
                pt: pt, key: 'goffeeJones', title: 'Goffee & Jones Culture', titleIcon: '🔲', rootFill: '#1E3A8A', rootStroke: '#1E40AF',
                yAxis: { label: 'Sociability', low: 'Low', high: 'High', desc: 'The degree of friendliness and warmth — the social bonds between people.' },
                xAxis: { label: 'Solidarity', low: 'Low', high: 'High', desc: 'The degree of task-focused common purpose — shared-goal intensity and output focus.' },
                zones: {
                    tl: { name: '☕ Commune', body: 'High sociability · Low solidarity', desc: 'Warm but unfocused — high friendliness, low shared purpose. Source: social but low goal alignment.', fill: '#EFF6FF', stroke: '#3B82F6', text: '#1E40AF' },
                    tr: { name: '🌐 Networked', body: 'High sociability · High solidarity', desc: 'The ideal, committed community — warm AND purpose-driven. Source: both surveys combined.', fill: '#DCFCE7', stroke: '#16A34A', text: '#166534' },
                    bl: { name: '🏝️ Fragmented', body: 'Low sociability · Low solidarity', desc: 'Loose and individualistic — weak bonds and weak shared purpose. Source: weak bonds and weak shared purpose.', fill: '#F1F5F9', stroke: '#64748B', text: '#334155' },
                    br: { name: '🏛️ Mercenary', body: 'Low sociability · High solidarity', desc: 'Task-driven and impersonal — high output focus, low warmth. Source: output-only metrics.', fill: '#FFF7ED', stroke: '#F97316', text: '#9A3412' }
                },
                footer: '🔲 Plot the culture by Sociability (Y) × Solidarity (X). Networked (top-right) is the goal; Mercenary, Commune and Fragmented are the failure modes. Type into any zone — all editable.'
            });
        } finally { model.endUpdate(); }
    });

