    FrameworkCatalog.register('blakeMouton', 'Blake–Mouton Managerial Grid', 'Enterprise & Org Design', function (pt, parent) {
        model.beginUpdate();
        try {
            // Quadrant (shared quadrant component): concern-for-people (Y) × concern-
            // for-production (X). The canonical 2×2 with editable zones.
            quadrant(parent, {
                pt: pt, key: 'blakeMouton', title: 'Blake–Mouton Managerial Grid', titleIcon: '🔲', rootFill: '#92400E', rootStroke: '#B45309',
                xAxis: { label: 'Concern for Production', low: 'Low', high: 'High', desc: 'How much the leader focuses on results, tasks, output and efficiency. Plot a leader further right the more they push the work.' },
                yAxis: { label: 'Concern for People', low: 'Low', high: 'High', desc: 'How much the leader focuses on people, relationships and the team. Plot a leader higher the more they invest in individuals.' },
                zones: {
                    tl: { name: '🤝 Country Club (1,9)', body: '[High people, low task]\nFriendly, low results', fill: '#F0FDF4', stroke: '#22C55E', text: '#166534', desc: 'High concern for people, low for production. Comfortable and friendly, but results suffer — a pleasant place that underperforms. Fill with the symptoms you see.' },
                    tr: { name: '⭐ Team Management (9,9)', body: '[High people, high task]\nTrust & performance', fill: '#F5F3FF', stroke: '#8B5CF6', text: '#6D28D9', desc: 'High concern for both, achieved through trust, respect and shared purpose. The model\'s ideal — note what makes this leader reach it.' },
                    bl: { name: '🏛️ Impoverished (1,1)', body: '[Low people, low task]\nMinimal effort', fill: '#FEF2F2', stroke: '#EF4444', text: '#991B1B', desc: 'Low concern for both — minimal effort, just enough to get by. Disengaged; neither people nor production are served.' },
                    br: { name: '📊 Authority-Compliance (9,1)', body: '[High task, low people]\nCommand & control', fill: '#FFF7ED', stroke: '#F97316', text: '#9A3412', desc: 'High concern for production, low for people — task-focused, compliance-driven, efficiency over relationships. Note where this shows up.' }
                },
                footer: '🔲 Plot a leader by concern for people (Y) × production (X).  Middle-of-Road (5,5) sits at the center.  Type into any zone — all editable.'
            });
        } finally { model.endUpdate(); }
    });

