    // ── Lencioni Five Dysfunctions — Actionable Pyramid + Diagnostic ──
    FrameworkCatalog.register('lencioni5', 'Lencioni Five Dysfunctions', 'Enterprise & Org Design', function (pt, parent) {
        model.beginUpdate();
        try {
            var W = 1400, PAD = 24, gap = 16;
            var halfW = (W - PAD * 2 - gap) / 2;

            var SEC = 'rounded=1;arcSize=12;html=1;fillColor=#1E3A8A;strokeColor=none;fontColor=#FFFFFF;fontSize=11;fontStyle=1;align=left;verticalAlign=middle;spacingLeft=10;';

            graph.insertVertex(parent, null, '🔺 Lencioni Five Dysfunctions — Team Diagnostic Pyramid', pt.x, pt.y, W, 52,
                STYLE_FRAMEWORK_ROOT + 'fillColor=#1E3A8A;strokeColor=#1E40AF;');

            // ① PYRAMID — bottom to top: Trust → Conflict → Commitment → Accountability → Results
            var s0Y = pt.y + 64;
            graph.insertVertex(parent, null, '① THE PYRAMID — Read from bottom (foundation) to top. Fix the lowest dysfunction first.', pt.x + PAD, s0Y, W - PAD * 2, 30, SEC);

            var funcs = [
                { icon: '🔒', name: '1. ABSENCE OF TRUST', body: 'Team members are not vulnerable with each other. They hide weaknesses, mistakes, and concerns.\n\nDiagnostic: Do people admit mistakes freely? Do they ask for help?\nScore: ___/5   Evidence: ___', fill: '#EFF6FF', stroke: '#3B82F6', text: '#1E40AF', w: W - PAD * 2, h: 80 },
                { icon: '⚔️', name: '2. FEAR OF CONFLICT', body: 'Artificial harmony replaces productive debate. Important issues are avoided or discussed behind closed doors.\n\nDiagnostic: Do debates happen openly? Are ideas challenged constructively?\nScore: ___/5   Evidence: ___', fill: '#F5F3FF', stroke: '#8B5CF6', text: '#5B21B6', w: W - PAD * 2 - gap * 1, h: 80 },
                { icon: '🤝', name: '3. LACK OF COMMITMENT', body: 'People do not buy in or commit to decisions. Ambiguity persists, and deadlines are missed.\n\nDiagnostic: Do people commit even when they disagree? Are decisions clear and timely?\nScore: ___/5   Evidence: ___', fill: '#FFF7ED', stroke: '#F97316', text: '#9A3412', w: W - PAD * 2 - gap * 2, h: 80 },
                { icon: '📊', name: '4. AVOIDANCE OF ACCOUNTABILITY', body: 'Team members avoid holding each other accountable for behaviors and performance.\n\nDiagnostic: Do peers call each other out? Are standards enforced equally?\nScore: ___/5   Evidence: ___', fill: '#FDF2F8', stroke: '#EC4899', text: '#9D174D', w: W - PAD * 2 - gap * 3, h: 80 },
                { icon: '🏆', name: '5. INATTENTION TO RESULTS', body: 'Focus is on个人 status and ego rather than collective outcomes.\n\nDiagnostic: Does the team prioritize results over个人 agendas?\nScore: ___/5   Evidence: ___', fill: '#FEF2F2', stroke: '#EF4444', text: '#991B1B', w: W - PAD * 2 - gap * 4, h: 80 }
            ];

            var pyramidY = s0Y + 34;
            funcs.forEach(function (f, i) {
                var offset = i * gap / 2;
                var cx = pt.x + PAD + offset;
                var cy = pyramidY + i * (f.h + 4);
                var node = graph.insertVertex(parent, null, f.icon + ' ' + f.name, cx, cy, f.w, f.h,
                    STYLE_CONTAINER + 'fillColor=' + f.fill + ';strokeColor=' + f.stroke + ';fontColor=' + f.text + ';swimlaneFillColor=' + f.fill + ';strokeWidth=2;align=center;verticalAlign=middle;fontSize=12;fontStyle=1;');
                graph.insertVertex(node, null, f.body, 6, 32, f.w - 12, f.h - 38,
                    CHILD_TEXT + 'fontSize=10;fontColor=' + COLOR_INK + ';spacingTop=4;spacingRight=4;spacingBottom=4;');
            });

            // ② TEAM ASSESSMENT TABLE
            var s1Y = pyramidY + 5 * (80 + 4) + 14;
            graph.insertVertex(parent, null, '② TEAM ASSESSMENT — Rate your team on each dysfunction (1-5)', pt.x + PAD, s1Y, W - PAD * 2, 30, SEC);

            var tHdrs = ['Dysfunction', 'Score (1-5)', 'Evidence / Examples', 'Root Cause', 'Fix Action', 'Owner'];
            var tW = [0.18, 0.10, 0.24, 0.20, 0.18, 0.10];
            var tY = s1Y + 34;
            var tX = pt.x + PAD;
            tHdrs.forEach(function (h, ci) {
                var w = (W - PAD * 2) * tW[ci];
                graph.insertVertex(parent, null, h, tX, tY, w - 4, 22,
                    'rounded=0;html=1;fillColor=#1E3A8A;strokeColor=none;fontSize=9;fontStyle=1;fontColor=#FFFFFF;align=left;verticalAlign=middle;spacingLeft=6;');
                tX += w;
            });
            var tRows = [
                ['Absence of Trust', '', '', '', '', ''],
                ['Fear of Conflict', '', '', '', '', ''],
                ['Lack of Commitment', '', '', '', '', ''],
                ['Avoidance of Accountability', '', '', '', '', ''],
                ['Inattention to Results', '', '', '', '', '']
            ];
            tRows.forEach(function (row, ri) {
                var ry = tY + 22 + ri * 24;
                var rx = pt.x + PAD;
                var rowFill = ri % 2 === 0 ? '#EFF6FF' : '#FFFFFF';
                row.forEach(function (val, ci) {
                    var w = (W - PAD * 2) * tW[ci];
                    var fontS = (ci === 0) ? ';fontStyle=1' : '';
                    graph.insertVertex(parent, null, val, rx, ry, w - 4, 20,
                        'text;html=1;rounded=1;arcSize=6;fillColor=' + rowFill + ';strokeColor=#E5E7EB;fontSize=9;fontColor=#334155' + fontS + ';align=left;verticalAlign=middle;spacingLeft=6;whiteSpace=wrap;placeholder=1;');
                    rx += w;
                });
            });

            // ③ DIAGNOSTIC
            var s2Y = tY + 22 + 5 * 24 + 8;
            graph.insertVertex(parent, null, '③ DIAGNOSTIC — The model requires fixing dysfunction at the base first', pt.x + PAD, s2Y, W - PAD * 2, 30, SEC);
            fwCallout(parent, { pt: { x: pt.x + PAD, y: s2Y + 34 }, text: 'Critical rule: You CANNOT fix upper dysfunctions without fixing the ones below. Trust is the foundation — no trust = no healthy conflict = no commitment = no accountability = no results. Start with team-building exercises focused on vulnerability. Typical timeline: 6-12 months for meaningful change.', variant: 'warning', width: W - PAD * 2 });

            // Metrics callout
            var mtrY = s2Y + 34 + 66 + 8;
            fwCallout(parent, { pt: { x: pt.x + PAD, y: mtrY }, text: 'Metrics: Team health survey score (quarterly). # of productive conflicts raised per sprint/quarter. Decision speed (days from discussion to commitment). Peer accountability conversations per month. Results vs targets delta. Re-assess every 90 days.', variant: 'success', width: W - PAD * 2 });

            graph.insertVertex(parent, null, '📋 Type into any box — all editable. Score each dysfunction 1-5. Fix the lowest-scoring dysfunction at the base FIRST.', pt.x, mtrY + 60 + 8, W, 30,
                'text;html=1;strokeColor=none;fillColor=#EFF6FF;align=left;verticalAlign=middle;fontFamily=' + BASE_FONT + ';fontSize=11;fontColor=#1E3A8A;');
        } finally { model.endUpdate(); }
    });

