    // ── Thomas-Kilmann Conflict Mode Instrument (TKI) ──
    FrameworkCatalog.register('tki', '🤝 Thomas-Kilmann Conflict Mode Instrument (TKI)', 'Team Effectiveness', function (pt, parent) {
        model.beginUpdate();
        try {
            quadrant(parent, {
                pt: pt, key: 'tki', title: '🤝 Conflict Modes (TKI)', titleIcon: '⚖️', rootFill: '#9D174D', rootStroke: '#BE185D',
                yAxis: { label: 'Assertiveness', low: 'Low', high: 'High', desc: 'How far you try to satisfy your own concerns. Plot higher the more you push for your position.' },
                xAxis: { label: 'Cooperativeness', low: 'Low', high: 'High', desc: 'How far you try to satisfy the other party’s concerns. Plot further right the more you yield.' },
                zones: {
                    tl: { name: '🤺 Competing', body: 'High assertiveness · Low cooperativeness', desc: 'Pursue your position at the other’s expense — use whatever power fits to win. Source: power/position.', fill: '#FEE2E2', stroke: '#DC2626', text: '#991B1B' },
                    tr: { name: '🧑‍🤝‍🧑 Collaborating', body: 'High assertiveness · High cooperativeness', desc: 'Dig into the issue with the other party to fully satisfy both sides. Source: joint problem-solving.', fill: '#DCFCE7', stroke: '#16A34A', text: '#166534' },
                    bl: { name: '🫣 Avoiding', body: 'Low assertiveness · Low cooperativeness', desc: 'Step away — ignore or postpone the issue to be handled later or by others. Source: risk/effort.', fill: '#F1F5F9', stroke: '#64748B', text: '#334155' },
                    br: { name: '💁 Accommodating', body: 'Low assertiveness · High cooperativeness', desc: 'Set aside your concerns to satisfy theirs — self-sacrifice to preserve harmony. Source: harmony/merit.', fill: '#DBEAFE', stroke: '#2563EB', text: '#1E40AF' }
                },
                center: { name: '⚖️ Compromising', body: 'Moderate · Moderate', desc: 'Negotiate an expedient middle ground that partially satisfies both. Source: give-and-take.', fill: '#FEF9C3', stroke: '#CA8A04', text: '#854D0E' },
                footer: '⚖️ Plot the conflict by assertiveness (Y) × cooperativeness (X). Pick the mode by the importance of the issue, the relationship, and time pressure — map each recurring conflict to its best-fit move.'
            });
        } finally { model.endUpdate(); }
    }, { keywords: 'conflict tki competing collaborating compromising avoiding accommodating assertiveness cooperativeness' });

