    FrameworkCatalog.register('gallupQ12', 'Gallup Q12 Engagement', 'Talent, HR & People-Systems', function (pt, parent) {
        model.beginUpdate();
        try {
            var cw = 200, ch = 116, gap = 16, cols = 4, rows = 3;
            graph.insertVertex(parent, null, '🌟 Gallup Q12 Engagement', pt.x, pt.y, cols * cw + (cols - 1) * gap, 48, STYLE_FRAMEWORK_ROOT + 'fillColor=#1E3A8A;strokeColor=#1E40AF;');
            var q = [
                'Q1 — I know what is expected of me at work.',
                'Q2 — I have the materials and equipment I need.',
                'Q3 — I have the opportunity to do what I do best every day.',
                'Q4 — In the last 7 days, I received recognition or praise.',
                'Q5 — My supervisor cares about me as a person.',
                'Q6 — Someone at work encourages my development.',
                'Q7 — My opinions seem to count at work.',
                'Q8 — The mission makes me feel my job is important.',
                'Q9 — My co-workers are committed to quality work.',
                'Q10 — I have a best friend at work.',
                'Q11 — Someone has talked to me about my progress (6 mo).',
                'Q12 — I have had opportunities to learn and grow (this year).'
            ];
            q.forEach(function (text, i) {
                var col = i % cols, row = Math.floor(i / cols);
                var x = pt.x + col * (cw + gap), y = pt.y + 84 + row * (ch + gap);
                var c = fwCard(parent, 'Q' + (i + 1), x, y, cw, ch, { fill: '#EFF6FF', stroke: '#3B82F6', text: '#1E40AF' }, text, 11);
                addCardTooltip(c, buildCardTooltip('Q' + (i + 1), text + ' Source: Q12 survey.', { framework: 'Gallup Q12', kind: 'Question' }));
            });
            graph.insertVertex(parent, null, '🌟 12 questions, scored 1–5. Low scores on Q1/Q2 (basics) and Q10/Q12 (bonding & growth) are the fastest levers. Type into any box — all editable.',
                pt.x, pt.y + 84 + rows * (ch + gap) + 2, cols * cw + (cols - 1) * gap, 36, 'text;html=1;strokeColor=none;fillColor=#EFF6FF;align=left;verticalAlign=middle;fontFamily=' + BASE_FONT + ';fontSize=11;fontColor=#1E40AF;');
        } finally { model.endUpdate(); }
    });

