    // ── Value Proposition Canvas — Actionable Customer/Value Fit ──
    FrameworkCatalog.register('valuePropCanvas', 'Value Proposition Canvas', 'Agile & Innovation', function (pt, parent) {
        model.beginUpdate();
        try {
            var W = 1400, PAD = 24, gap = 16;
            var halfW = (W - PAD * 2 - gap) / 2;

            var SEC = 'rounded=1;arcSize=12;html=1;fillColor=#0D9488;strokeColor=none;fontColor=#FFFFFF;fontSize=11;fontStyle=1;align=left;verticalAlign=middle;spacingLeft=10;';

            graph.insertVertex(parent, null, '💎 Value Proposition Canvas — Customer Profile + Value Map Fit', pt.x, pt.y, W, 52,
                STYLE_FRAMEWORK_ROOT + 'fillColor=#115E59;strokeColor=#0D9488;');

            // ① CUSTOMER PROFILE (left)
            var s0Y = pt.y + 64;
            graph.insertVertex(parent, null, '① CUSTOMER PROFILE — Understand the customer side', pt.x + PAD, s0Y, halfW, 30, SEC);

            var custCards = [
                { icon: '📋', name: 'CUSTOMER JOBS', body: 'What functional, social, or emotional jobs is your customer trying to get done?\n\nFunctional: ___\nSocial: ___\nEmotional: ___\n\nRank importance: 1=low, 5=critical', fill: '#EFF6FF', stroke: '#3B82F6', text: '#1E40AF' },
                { icon: '😣', name: 'PAINS', body: 'What annoys your customer before, during, or after getting the job done?\n\nUndesired outcomes: ___\nObstacles: ___\nRisks: ___\n\nRank severity: 1=mild, 5=blocking', fill: '#FEF2F2', stroke: '#EF4444', text: '#991B1B' },
                { icon: '🌟', name: 'GAINS', body: 'What outcomes and benefits does your customer want?\n\nRequired gains: ___\nExpected gains: ___\nDesired gains: ___\nUnexpected gains: ___\n\nRank importance: 1=nice, 5=must-have', fill: '#F0FDF4', stroke: '#22C55E', text: '#166534' }
            ];
            custCards.forEach(function (c, i) {
                fwCard(parent, c.icon + ' ' + c.name, pt.x + PAD, s0Y + 34 + i * (150 + gap), halfW, 150, { fill: c.fill, stroke: c.stroke, text: c.text }, c.body, 10);
            });

            // ② VALUE MAP (right)
            graph.insertVertex(parent, null, '② VALUE MAP — How your product addresses each customer element', pt.x + PAD + halfW + gap, s0Y, halfW, 30, SEC);

            var valCards = [
                { icon: '📦', name: 'PRODUCTS & SERVICES', body: 'List your products/services that address customer jobs.\n\nList each: ___\nWhich job does it address? ___\n\nIs it a must-have or nice-to-have?', fill: '#F5F3FF', stroke: '#8B5CF6', text: '#5B21B6' },
                { icon: '🛡️', name: 'PAIN RELIEVERS', body: 'How does each product/service reduce customer pains?\n\nPain relieved: ___\nReliever: ___\n\nDoes it eliminate, reduce, or just distract?', fill: '#FFF7ED', stroke: '#F97316', text: '#9A3412' },
                { icon: '🚀', name: 'GAIN CREATORS', body: 'How does each product/service create customer gains?\n\nGain addressed: ___\nCreator: ___\n\nDoes it fully deliver, partially deliver, or create new gains?', fill: '#FDF2F8', stroke: '#EC4899', text: '#9D174D' }
            ];
            valCards.forEach(function (c, i) {
                fwCard(parent, c.icon + ' ' + c.name, pt.x + PAD + halfW + gap, s0Y + 34 + i * (150 + gap), halfW, 150, { fill: c.fill, stroke: c.stroke, text: c.text }, c.body, 10);
            });

            // Connectors between sides
            for (var i = 0; i < 3; i++) {
                var fromX = pt.x + PAD + halfW;
                var toX = pt.x + PAD + halfW + gap;
                var cy = s0Y + 34 + i * (150 + gap) + 75;
                graph.insertEdge(parent, null, '', null, null,
                    'edgeStyle=orthogonalEdgeStyle;rounded=1;orthogonalLoop=1;html=1;strokeWidth=2;strokeColor=#0D9488;endArrow=none;exitX=1;exitY=0.5;exitDx=0;exitDy=0;entryX=0;entryY=0.5;entryDx=0;entryDy=0;');
            }

            // ③ FIT ASSESSMENT
            var s1Y = s0Y + 34 + 3 * (150 + gap) + 10;
            graph.insertVertex(parent, null, '③ FIT ASSESSMENT — How well does your Value Map match the Customer Profile?', pt.x + PAD, s1Y, W - PAD * 2, 30, SEC);

            var fitHdrs = ['Customer Job', 'Pain Relieved?', 'Gain Delivered?', 'Fit Score (1-5)', 'Gap / Action'];
            var fitW = [0.22, 0.16, 0.16, 0.14, 0.32];
            var fitY = s1Y + 34;
            var fitX = pt.x + PAD;
            fitHdrs.forEach(function (h, ci) {
                var w = (W - PAD * 2) * fitW[ci];
                graph.insertVertex(parent, null, h, fitX, fitY, w - 4, 22,
                    'rounded=0;html=1;fillColor=#0D9488;strokeColor=none;fontSize=9;fontStyle=1;fontColor=#FFFFFF;align=left;verticalAlign=middle;spacingLeft=6;');
                fitX += w;
            });
            var fitRows = [['', '', '', '', ''], ['', '', '', '', ''], ['', '', '', '', ''], ['', '', '', '', '']];
            fitRows.forEach(function (row, ri) {
                var ry = fitY + 22 + ri * 24;
                var rx = pt.x + PAD;
                var rowFill = ri % 2 === 0 ? '#F0FDFA' : '#FFFFFF';
                row.forEach(function (val, ci) {
                    var w = (W - PAD * 2) * fitW[ci];
                    graph.insertVertex(parent, null, val, rx, ry, w - 4, 20,
                        'text;html=1;rounded=1;arcSize=6;fillColor=' + rowFill + ';strokeColor=#E5E7EB;fontSize=9;fontColor=#334155;align=left;verticalAlign=middle;spacingLeft=6;whiteSpace=wrap;placeholder=1;');
                    rx += w;
                });
            });

            fwCallout(parent, { pt: { x: pt.x + PAD, y: fitY + 22 + 4 * 24 + 8 }, text: 'Fit Score Guide: 5 = perfect fit (pain fully relieved, gain fully delivered). 3 = partial fit. 1 = no fit. Target: all critical jobs at 4+. If average fit < 3, your Value Proposition needs redesign. Update after every 5 customer interviews.', variant: 'tip', width: W - PAD * 2 });

            graph.insertVertex(parent, null, '📋 Type into any box — all editable. The 1:1 mapping between Pain Relievers ↔ Pains and Gain Creators ↔ Gains is what creates product-market fit.', pt.x, fitY + 22 + 4 * 24 + 68 + 8, W, 30,
                'text;html=1;strokeColor=none;fillColor=#F0FDFA;align=left;verticalAlign=middle;fontFamily=' + BASE_FONT + ';fontSize=11;fontColor=#0D9488;');
        } finally { model.endUpdate(); }
    });

