    // ── Business Plan (hierarchical: Part → Section → Subsection) ──
    FrameworkCatalog.register('businessPlan', 'Business Plan', 'Strategy', function (pt, parent) {
        model.beginUpdate();
        try {
            var rootW = 1160, rootH = 48, hdrH = 32, lineH = 22, colW = 550, gap = 40;
            graph.insertVertex(parent, null, '📊 Business Plan', pt.x, pt.y, rootW, rootH,
                STYLE_FRAMEWORK_ROOT + 'fillColor=#1E3A8A;strokeColor=#1E40AF;');

            var parts = [
                {
                    title: '📘 Part I — Planning Foundations',
                    x: pt.x + 20,
                    items: [
                        { s: '🎯 Setting Your Vision', items: ['2.1 Crafting Mission Statement', '2.2 Defining Vision Statement', '2.3 Establishing Core Values'] },
                        { s: '🔍 Market Analysis', items: ['3.1 Understanding Your Market', '3.2 Identifying Target Audience', '3.3 Competitive Analysis', '3.4 SWOT Analysis'] },
                        { s: '🧭 Strategic Planning', items: ['4.1 Setting Long-term Objectives', '4.2 Developing Short-term Goals', '4.3 Selecting Strategies to Achieve Objectives', '4.4 Milestones & KPIs'] }
                    ]
                },
                {
                    title: '📗 Part II — Crafting Your Plan',
                    x: pt.x + 20 + colW + gap,
                    items: [
                        { s: '📝 The Executive Summary', items: ['5.1 Components of an Effective Executive Summary', '5.2 Writing Tips for Maximum Impact'] },
                        { s: '🏢 Company Description', items: ['6.1 Business Model Canvas', '6.2 Company Structure', '6.3 History and Background', '6.4 Legal and Regulatory Considerations'] },
                        { s: '📦 Products and Services', items: ['7.1 Detailed Description of Products and Services', '7.2 Development and Production Process', '7.3 Intellectual Property Considerations', '7.4 Future Offerings'] },
                        { s: '📣 Marketing and Sales Strategy', items: ['8.1 Marketing and Promotional Strategies', '8.2 Pricing Strategy', '8.3 Sales Plan', '8.4 Distribution Channels'] },
                        { s: '⚙️ Operational Plan', items: ['9.1 Operational Workflow', '9.2 Supplier and Vendor Management', '9.3 Facilities and Location', '9.4 Technology Needs', '9.5 Staffing and Human Resources'] },
                        { s: '💰 Financial Plan', items: ['10.1 Revenue Model', '10.2 Cost Structure', '10.3 Funding Requirements and Strategy', '10.4 Financial Projections: P&L, Balance Sheet, Cash Flow', '10.5 Break-even Analysis'] },
                        { s: '⚠️ Risk Management', items: ['11.1 Identifying Potential Risks', '11.2 Mitigation Strategies', '11.3 Contingency Planning'] }
                    ]
                }
            ];

            var startY = pt.y + rootH + 28;
            parts.forEach(function (part, pi) {
                var py = startY;
                var partHeader = graph.insertVertex(parent, null, part.title, part.x, py, colW, 38,
                    STYLE_FRAMEWORK_ROOT + 'fillColor=#334155;strokeColor=#1E293B;fontSize=13;');
                py += 38 + 16;
                part.items.forEach(function (sec, i) {
                    var subH = sec.items.length * lineH;
                    var chh = hdrH + subH + 12;
                    var p = ORG_PALETTE[i % ORG_PALETTE.length];
                    var node = graph.insertVertex(parent, null, sec.s, part.x, py, colW, chh,
                        STYLE_CONTAINER + 'fillColor=' + p.fill + ';strokeColor=' + p.stroke + ';fontColor=' + p.text + ';strokeWidth=2;');
                    graph.insertVertex(node, null, sec.items.join('\n'), 4, hdrH, colW - 8, subH, CHILD_TEXT + 'fontSize=11;fontColor=' + COLOR_INK + ';');
                    graph.insertEdge(parent, null, '', partHeader, node, STYLE_FW_EDGE + 'strokeColor=#94A3B8;strokeWidth=1;');
                    py += chh + 16;
                });
            });
        } finally { model.endUpdate(); }
    });

    // ───────────────────────────────────────────────────────────────────
    // JOB SEARCH FRAMEWORKS — career-narrative & resume-bullet frameworks
    // ───────────────────────────────────────────────────────────────────
    function jobFramework(key, label, blocks, rootColor) {
        FrameworkCatalog.register(key, label, 'Job Search', function (pt, parent) {
            model.beginUpdate();
            try {
                var rootW = 940, rootH = 56;
                rootColor = rootColor || { fill: '#0F766E', stroke: '#115E59' };
                graph.insertVertex(parent, null, label, pt.x, pt.y, rootW, rootH,
                    STYLE_FRAMEWORK_ROOT + 'fillColor=' + rootColor.fill + ';strokeColor=' + rootColor.stroke + ';verticalAlign=middle;align=center;fontSize=16;fontStyle=1;');
                var cw = 900, hdrH = 34, gy = 22;
                var startY = pt.y + rootH + 24;
                blocks.forEach(function (b, i) {
                    var bodyLines = Math.max(1, Math.ceil((b.body || '').length / 78));
                    var ch = hdrH + 16 + bodyLines * 18 + 12;
                    var p = ORG_PALETTE[i % ORG_PALETTE.length];
                    var x = pt.x + (rootW - cw) / 2;
                    var y = startY + i * (ch + gy);
                    var node = graph.insertVertex(parent, null, b.title, x, y, cw, ch,
                        STYLE_CONTAINER + 'fillColor=' + p.fill + ';strokeColor=' + p.stroke + ';fontColor=' + p.text + ';strokeWidth=2;fontSize=13;');
                    if (b.body) {
                        graph.insertVertex(node, null, b.body, 6, hdrH, cw - 12, ch - hdrH - 6, CHILD_TEXT + 'fontSize=12;fontColor=' + COLOR_INK + ';spacingTop=4;');
                    }
                    addCardTooltip(node, buildCardTooltip(b.title, b.body, { framework: label }));
                });
            } finally { model.endUpdate(); }
        }, { kind: 'job', blocks: blocks });
    }

