    // ═════════════════════════════════════════════════════════════════
    // TEMPLATE INTEGRATION — inject all frameworks into native dialog
    // Draw.io uses NewDialog which fetches from EditorUi.templateFile.
    // Blob URLs break the URL routing (prepends TEMPLATE_PATH), so we
    // monkey-patch mxUtils.get to intercept our blob URLs and return
    // cached XML directly.
    // Deferred with setTimeout so it never blocks plugin init or keybindings.
    // ═══════════════════════════════════════════════════════════════════
    setTimeout(function () {
        try {
            var _xmlCache = {};

            // draw.io's Graph subclass adds getAdaptiveColors (and other view
            // helpers) that the base mxGraph lacks. Constructing a plain
            // mxGraph therefore throws during background validation, which made
            // every generateDiagramXml() fall back to empty XML. Stub it on the
            // base prototype so our offscreen temp graphs build real framework
            // XML. (draw.io's real graph keeps its own implementation.)
            if (typeof mxGraph !== 'undefined' && typeof mxGraph.prototype.getAdaptiveColors !== 'function') {
                mxGraph.prototype.getAdaptiveColors = function () { return {}; };
            }

            function escXml(s) {
                return String(s).replace(/&/g, '&amp;').replace(/</g, '&lt;')
                    .replace(/>/g, '&gt;').replace(/"/g, '&quot;');
            }

            function generateDiagramXml(entry, atPoint) {
                // Build on the REAL graph, then deep-clone the newly added cells into
                // a throwaway model for encoding and remove the originals. This is the
                // SAME pipeline the Insert Framework picker reuses (via BuildFrameworkXml)
                // so frameworks render identically to the native template dialog.
                atPoint = atPoint || { x: 40, y: 40 };
                var label = (entry && entry.label) || 'Framework';
                var key = (entry && entry.key) || '?';
                var newCells = [];
                var grp = null, toRemove = null;
                try {
                    var parent = graph.getDefaultParent();
                    var before = {};
                    model.beginUpdate();
                    try {
                        var cnt = model.getChildCount(parent);
                        for (var i = 0; i < cnt; i++) { before[model.getChildAt(parent, i).getId()] = true; }
                        try { entry.builder(atPoint, parent); } catch (e) { /* partial is fine */ }
                        cnt = model.getChildCount(parent);
                        for (var j = 0; j < cnt; j++) {
                            var c = model.getChildAt(parent, j);
                            if (!before[c.getId()]) newCells.push(c);
                        }
                        if (newCells.length === 0) throw new Error('builder produced no cells');
                        // Group every shape into ONE resizable/movable unit so the
                        // framework inserts as a single object instead of loose, scattered
                        // shapes. Falls back to a flat list if grouping is unavailable.
                        try {
                            if (newCells.length > 1) {
                                grp = graph.groupCells(null, 0, newCells);
                                // Label the group with the framework name so it matches the
                                // picker's behaviour (the inserted object is self-describing).
                                try { if (grp && model.isVertex && model.isVertex(grp)) model.setValue(grp, label); } catch (se) { }
                            } else {
                                grp = newCells[0];
                            }
                        } catch (ge) { grp = null; }
                        toRemove = (grp != null) ? grp : newCells;
                    } finally {
                        model.endUpdate();
                    }
                    var cellsToEncode = (grp != null) ? [grp] : newCells;
                    var clones = graph.cloneCells(cellsToEncode, true);
                    var tmpModel = new mxGraphModel();
                    tmpModel.beginUpdate();
                    for (var k = 0; k < clones.length; k++) { tmpModel.add(tmpModel.getRoot(), clones[k]); }
                    tmpModel.endUpdate();
                    var modelXml = mxUtils.getXml(new mxCodec().encode(tmpModel));
                    return '<mxfile><diagram name="' + escXml(label) + '">' + modelXml + '</diagram></mxfile>';
                } catch (e2) {
                    console.error('[Consultant Toolkit] template gen failed for ' + key, e2);
                    return '<mxfile><diagram name="' + escXml(label) + '"><mxGraphModel><root><mxCell id="0"/><mxCell id="1" parent="0"/></root></mxGraphModel></diagram></mxfile>';
                } finally {
                    // Robustly remove every cell we added to the REAL graph so the
                    // picker / template dialog never leaves originals behind (which
                    // would then duplicate with the imported copy). We remove via the
                    // model directly (not graph.removeCells): removeCells can throw on
                    // edge/terminal handling for some frameworks and its error used to
                    // be swallowed, silently leaving the originals on the canvas and
                    // producing two stacked copies of the same framework.
                    try {
                        var _del = (toRemove != null)
                            ? (Array.isArray(toRemove) ? toRemove.slice() : [toRemove])
                            : [];
                        // Sweep any builder-added cells that escaped grouping (e.g.
                        // edges groupCells didn't nest) by matching them against the
                        // cells we captured as new during the build.
                        try {
                            var _p = graph.getDefaultParent();
                            var _n = model.getChildCount(_p);
                            for (var _i = 0; _i < _n; _i++) {
                                var _c = model.getChildAt(_p, _i);
                                if (newCells.indexOf(_c) >= 0) _del.push(_c);
                            }
                        } catch (e) { /* ignore */ }
                        // De-duplicate before removing.
                        var _seen = {}, _uniq = [];
                        for (var _d = 0; _d < _del.length; _d++) {
                            var _cell = _del[_d];
                            if (_cell && _cell.getId && _seen[_cell.getId()] == null) {
                                _seen[_cell.getId()] = 1;
                                _uniq.push(_cell);
                            }
                        }
                        model.beginUpdate();
                        try {
                            for (var _k = 0; _k < _uniq.length; _k++) {
                                try { if (model.getParent(_uniq[_k]) != null) model.remove(_uniq[_k]); } catch (e) { /* ignore */ }
                            }
                        } finally { model.endUpdate(); }
                    } catch (e3) { /* last resort: leave nothing behind if at all possible */ }
                }
            }

            // Expose the build→group→clone→encode pipeline so the Insert Framework
            // picker can reuse the exact same rendering path as this template dialog.
            BuildFrameworkXml = generateDiagramXml;

            // --- Inject our frameworks into draw.io's native template dialog ---
            // We leave EditorUi.templateFile pointing at draw.io's real index.xml and
            // intercept that fetch to inject our frameworks. Each framework's diagram
            // XML is generated on demand (lazily) when NewDialog requests its
            // "consultantkit://<key>" URL. Per-template generation runs the builder on
            // the REAL graph (the same proven path the Framework Picker uses), then
            // clones+encodes the new cells and removes them — no fragile temp mxGraph.
            var _scheme = 'consultantkit://';
            var _tplCache = {};

            function entryByKey(key) {
                // Multi-section entries use suffixed keys like "swot__product".
                // Strip the suffix to resolve back to the base entry.
                var baseKey = key.indexOf('__') !== -1 ? key.split('__')[0] : key;
                var found = null;
                FrameworkCatalog.getAll().forEach(function (e) {
                    if (e.key === baseKey) found = e;
                });
                return found;
            }

            // --- Build OUR template entries (injected into draw.io's built-in index) ---
            // Each framework appears in its primary section AND any additional sections
            // listed in FRAMEWORK_META[key].sections. Tags include label, group, and
            // FRAMEWORK_META tags so everything is searchable in draw.io's native
            // template dialog (⌘⇧T).
            function ourEntriesXml() {
                var s = '';
                FrameworkCatalog.getAll().forEach(function (entry) {
                    // Collect all sections this framework should appear in
                    var meta = (FRAMEWORK_META && FRAMEWORK_META[entry.key]) || {};
                    var sections = [entry.group].concat(meta.sections || []);

                    // Build rich tag set from label + group + FRAMEWORK_META tags
                    var words = entry.label.toLowerCase().split(/\s+/).filter(Boolean);
                    var grpWords = entry.group.toLowerCase().split(/\s+/).filter(Boolean);
                    var metaTags = (meta.tags || []).map(function (t) { return t.toLowerCase(); });
                    var tagTokens = [entry.key.toLowerCase(), entry.label.toLowerCase()]
                        .concat(words).concat(entry.group.toLowerCase()).concat(grpWords)
                        .concat(metaTags);
                    var seen = {}, uniq = [];
                    tagTokens.forEach(function (tk) { if (!seen[tk]) { seen[tk] = 1; uniq.push(tk); } });
                    var tagsStr = escXml(uniq.join(';'));

                    // Emit a <template> entry for each section
                    var emittedSections = {};
                    sections.forEach(function (sec) {
                        if (emittedSections[sec]) return;
                        emittedSections[sec] = true;
                        // Use base key for primary section, suffixed for additional sections
                        // so draw.io's NewDialog indexes them under different section tabs.
                        var tplKey = (sec === entry.group) ? entry.key : entry.key + '__' + sec.toLowerCase().replace(/[^a-z0-9]+/g, '_');
                        s += '  <template section="' + escXml(sec) +
                            '" url="' + _scheme + tplKey +
                            '" title="' + escXml(entry.label) +
                            '" name="' + escXml(entry.label) +
                            '" tags="' + tagsStr + '"/>\n';
                    });
                });
                return s;
            }

            // --- Monkey-patch mxUtils.get ---
            // We do NOT replace EditorUi.templateFile. Instead we intercept draw.io's
            // OWN built-in index fetch and inject our frameworks into it. Because the
            // combined index is served in response to the REAL index URL, draw.io keeps
            // resolving the built-in templates' relative urls against TEMPLATE_PATH
            // (so their thumbnails/content keep working). Our entries use the
            // consultantkit:// scheme and are generated on demand when clicked.
            // IMPORTANT: built-ins are NEVER replaced. We cache the real index and
            // always append our entries to it; on fetch failure we fall back to the
            // cached index (or let draw.io's own error path run) rather than serving
            // only our entries.
            var _origGet = mxUtils.get;
            var _builtinIndex = null;
            mxUtils.get = function (url, onload, onerror, timeout, onprogress) {
                function serve(xml, status) {
                    window.setTimeout(function () {
                        if (onload) {
                            onload({
                                getStatus: function () { return (status != null) ? status : 200; },
                                getText: function () { return xml; },
                                getXml: function () { return mxUtils.parseXml(xml); },
                                getResponseHeaders: function () { return ''; }
                            });
                        }
                    }, 0);
                    return { abort: function () { } };
                }
                function serveCombined(builtinXml) {
                    // Only ever serve built-ins + ours. If we have NO valid built-in
                    // index (neither the current fetch nor a previous cache), serve
                    // nothing at all — never replace built-ins with our-only entries.
                    var src = (builtinXml && builtinXml.indexOf('</templates>') !== -1) ? builtinXml
                        : (_builtinIndex && _builtinIndex.indexOf('</templates>') !== -1) ? _builtinIndex
                            : null;
                    if (src == null) return;
                    serve(src.replace('</templates>', ourEntriesXml() + '</templates>'));
                }
                if (typeof url === 'string') {
                    // Our per-template content (NewDialog prepends TEMPLATE_PATH + '/'
                    // to non-http(s) urls, so match the scheme anywhere in the string).
                    var m = /consultantkit:\/\/([^/?#]+)/.exec(url);
                    if (m) {
                        var key = m[1];
                        var entry = entryByKey(key);
                        if (entry) {
                            if (_tplCache[key] == null) {
                                _tplCache[key] = generateDiagramXml(entry);
                            }
                            return serve(_tplCache[key]);
                        }
                    }
                    // Draw.io's built-in template index: inject our frameworks, but
                    // ALWAYS keep the built-ins. Cache the real index and append to it.
                    if (/index\.xml(\?|$)/.test(url) && url.indexOf(_scheme) === -1) {
                        _origGet.call(mxUtils, url, function (req) {
                            var txt = (req && typeof req.getText === 'function') ? req.getText() : '';
                            _builtinIndex = txt;
                            serveCombined(txt);
                        }, function () {
                            if (_builtinIndex != null) {
                                serveCombined(_builtinIndex);
                            } else if (typeof onerror === 'function') {
                                onerror();
                            }
                            // else: do nothing — built-ins load as draw.io sees fit
                            // (never replace them with our-only entries).
                        });
                        return { abort: function () { } };
                    }
                }
                return _origGet.apply(this, arguments);
            };

            // NewDialog.tagsList is keyed by templateFile URL and must stay a valid
            // object (never null — it reads tagsList[templateFile] and would throw).
            if (typeof NewDialog !== 'undefined' && NewDialog.tagsList == null) {
                NewDialog.tagsList = {};
            }
        } catch (e) {
            console.error('[Consultant Toolkit] template integration failed:', e);
        }
    }, 2000);

    // --- ORIGINAL ACTIONS ---
    ui.actions.addAction('toggleFormatPanel', function () {
        var p = ui.actions.get('format');
        if (!p) return;
        p.funct();
        var tryArrange = function (attempts) {
            try {
                var fmt = ui.format;
                if (!fmt || !fmt.container) return;
                var label = (typeof mxResources !== 'undefined') ? mxResources.get('arrange') : 'Arrange';
                var titles = fmt.container.querySelectorAll('.geFormatTitle');
                for (var i = 0; i < titles.length; i++) {
                    var t = titles[i];
                    var title = t.getAttribute('title') || '';
                    var text = (t.textContent || '').trim();
                    if (title === label || text === label) { t.click(); return; }
                }
                if (titles.length > 0 && graph.getSelectionCount() > 0) {
                    titles[titles.length - 1].click();
                }
            } catch (e) { /* ignore */ }
            if (attempts > 0) {
                setTimeout(function () { tryArrange(attempts - 1); }, 30);
            }
        };
        tryArrange(6);
    });

    ui.actions.addAction('insertPage', function () {
        if (typeof ui.insertPage === 'function') { ui.insertPage(); return; }
        if (typeof ui.addPage === 'function') { ui.addPage(); return; }
    });
