    // --- ENTERPRISE ACTIONS ---

    ui.actions.addAction('insertBusinessFramework', function () {
        showFrameworkPicker(FrameworkCatalog.getCategories(), 'minto', function (type) {
            if (!type) return;
            type = type.toLowerCase();
            var pt = getPoint();
            var parent = graph.getDefaultParent();

            // Find the matching catalog entry to decide how to insert it.
            var entry = null;
            FrameworkCatalog.getAll().forEach(function (e) { if (e.key === type) entry = e; });

            // Prompt-based frameworks (builders that call showPrompt) insert
            // asynchronously inside their own prompt callback, so we use the
            // original direct-insert path for them — it already renders fine.
            var usesPrompt = !!(entry && entry.builder && entry.builder.toString().indexOf('showPrompt') >= 0);

            if (!usesPrompt && typeof BuildFrameworkXml === 'function') {
                // Reuse the EXACT template pipeline (build → group → clone →
                // encode → decode → importCells). This is the proven path that
                // renders every framework correctly, including nested cards.
                var xml = null;
                try { xml = BuildFrameworkXml(entry, pt); } catch (e) { xml = null; }
                if (xml) {
                    var ok = insertFrameworkFromXml(xml, pt, parent, entry);
                    if (ok) return;
                }
                // Fall through to the direct path if XML generation failed.
            }

            // Direct path (prompt-based frameworks, or fallback).
            try {
                FrameworkCatalog.insert(type, pt, parent);
            } catch (e) {
                console.error('[Consultant Toolkit] insert failed for "' + type + '":', e);
            }
        });
    });

    // Cmd+Shift+T → Draw.io's built-in template dialog
