    ui.actions.addAction('generateMermaid', function () { generateMermaidFromSelection(); });

    ui.actions.addAction('clearCanvas', function () {
        var childCount = model.getChildCount(graph.getDefaultParent());
        if (childCount === 0) return;

        var container = document.createElement('div');
        container.style.padding = '16px';
        container.style.minWidth = '280px';
        var msg = document.createElement('div');
        msg.style.fontFamily = 'Excalifont';
        msg.style.fontSize = '13px';
        msg.innerText = 'Clear entire canvas? This cannot be undone.';
        container.appendChild(msg);
        var btnRow = document.createElement('div');
        btnRow.style.cssText = 'text-align:right;margin-top:14px;';
        var cancelBtn = document.createElement('button');
        cancelBtn.innerText = 'Cancel';
        cancelBtn.style.cssText = 'margin-right:8px;padding:4px 16px;font-size:13px;cursor:pointer;font-family:Excalifont;';
        cancelBtn.onclick = function () { ui.hideDialog(); };
        var okBtn = document.createElement('button');
        okBtn.innerText = 'Clear';
        okBtn.style.cssText = 'padding:4px 16px;font-size:13px;cursor:pointer;font-family:Excalifont;background:#DC2626;color:#fff;border:none;border-radius:4px;';
        okBtn.onclick = function () {
            ui.hideDialog();
            var parent = graph.getDefaultParent();
            model.beginUpdate();
            try {
                var cells = [];
                var cc = model.getChildCount(parent);
                for (var i = 0; i < cc; i++) cells.push(model.getChildAt(parent, i));
                if (cells.length > 0) model.remove(parent, cells, true);
            } finally { model.endUpdate(); }
        };
        btnRow.appendChild(cancelBtn);
        btnRow.appendChild(okBtn);
        container.appendChild(btnRow);
        ui.showDialog(container, 340, 160, true, false);
    });

