    // --- SHORTCUTS HELP (Cmd+Shift+?) ---

    // --- GENERATE MERMAID FROM SELECTION (Cmd+`) ---
    function sanitizeMermaidLabel(s) {
        s = String(s == null ? '' : s);
        s = s.replace(/\r?\n/g, ' ').replace(/\s+/g, ' ').trim();
        s = s.replace(/"/g, "'").replace(/\[/g, '(').replace(/\]/g, ')').replace(/\|/g, '/');
        if (s.length > 60) s = s.substring(0, 57) + '...';
        return s;
    }
    function generateMermaidFromSelection() {
        var cells = graph.getSelectionCells();
        var verts = cells.filter(function (c) { return model.isVertex(c); });
        var edges = cells.filter(function (c) { return model.isEdge(c); });
        if (verts.length === 0) {
            var hint = document.createElement('div');
            hint.style.cssText = 'padding:16px;width:320px;max-width:92vw;font-family:Excalifont;font-size:13px;color:#64748B;';
            hint.innerText = 'Select one or more nodes (and optional connectors), then press ⌘` to generate a Mermaid diagram.';
            ui.showDialog(hint, 360, 150, true, false);
            return;
        }
        var idMap = {};
        var lines = ['graph TD'];
        verts.forEach(function (v, i) {
            var id = 'N' + i;
            idMap[v.getId()] = id;
            lines.push('    ' + id + '["' + sanitizeMermaidLabel(v.value) + '"]');
        });
        edges.forEach(function (e) {
            var s = (typeof e.getSource === 'function') ? e.getSource() : null;
            var t = (typeof e.getTarget === 'function') ? e.getTarget() : null;
            if (!s || !t || !idMap[s.getId()] || !idMap[t.getId()]) return;
            var lbl = sanitizeMermaidLabel(e.value);
            if (lbl) lines.push('    ' + idMap[s.getId()] + ' -->|"' + lbl + '"| ' + idMap[t.getId()]);
            else lines.push('    ' + idMap[s.getId()] + ' --> ' + idMap[t.getId()]);
        });
        var mermaid = lines.join('\n');

        var container = document.createElement('div');
        container.style.cssText = 'padding:16px;width:440px;max-width:94vw;font-family:Excalifont;';
        var title = document.createElement('div');
        title.style.cssText = 'font-size:14px;font-weight:bold;margin-bottom:8px;color:#1E293B;';
        title.innerText = '🧬 Mermaid from selection (' + verts.length + ' nodes, ' + edges.length + ' edges)';
        container.appendChild(title);
        var ta = document.createElement('textarea');
        ta.value = mermaid;
        ta.readOnly = true;
        ta.style.cssText = 'width:100%;height:220px;box-sizing:border-box;padding:8px;font-family:monospace;font-size:12px;border:1px solid #CBD5E1;border-radius:6px;background:#F8FAFC;resize:none;';
        container.appendChild(ta);
        var row = document.createElement('div');
        row.style.cssText = 'text-align:right;margin-top:10px;font-size:12px;';
        var copy = document.createElement('span');
        copy.style.cssText = 'color:#6366F1;cursor:pointer;text-decoration:underline;';
        copy.innerText = 'Copy to clipboard';
        copy.onclick = function () {
            try { if (ta.select) ta.select(); if (document.execCommand) document.execCommand('copy'); } catch (err) { }
            copy.innerText = 'Copied ✓';
        };
        row.appendChild(copy);
        container.appendChild(row);
        ui.showDialog(container, 460, 340, true, false);
    }

    // --- HOTKEYS ---
    var k = ui.keyHandler;

    // Single source of truth for every keybinding this plugin registers.
    // control = Cmd (mac) / Ctrl (win). draw.io's KeyHandler stores bindings
    // in four maps selected by (shift, control) state; we snapshot its
    // pre-existing bindings so we can report any collision with built-ins.
    var MY_BINDINGS = [
        { code: 78, shift: true, control: true, action: 'insertPage', label: '⌘⇧N' },
        { code: 190, shift: true, control: true, action: 'cycleShape', label: '⌘⇧.' },
        { code: 89, shift: true, control: true, action: 'layoutPicker', label: '⌘⇧Y' },
        { code: 77, shift: true, control: true, action: 'openMermaid', label: '⌘⇧M' },
        { code: 186, shift: true, control: false, action: 'toggleFormatPanel', label: '⌘;' },
        { code: 66, shift: true, control: true, action: 'insertBusinessFramework', label: '⌘⇧B' },
        { code: 84, shift: true, control: true, action: 'insertTemplate', label: '⌘⇧T' },
        { code: 73, shift: true, control: true, action: 'insertIcon', label: '⌘⇧I' },
        { code: 8, shift: true, control: true, action: 'clearCanvas', label: '⌘⇧⌫' },
        { code: 57, shift: false, control: true, action: 'fillColorPicker', label: '⌘9' },
        { code: 192, shift: false, control: true, action: 'generateMermaid', label: '⌘`' },
        { code: 191, shift: true, control: true, action: 'shortcutsHelp', label: '⌘⇧?' },
        { code: 48, shift: false, control: true, action: 'strokeColorPicker', label: '⌘0' },
        { code: 219, shift: false, control: true, action: 'decreaseFont', label: '⌘[' },
        { code: 221, shift: false, control: true, action: 'increaseFont', label: '⌘]' },
        { code: 71, shift: true, control: true, action: 'forceSequence', label: '⌘⇧G' },
        { code: 83, shift: true, control: true, action: 'forceStartupSequence', label: '⌘⇧S' }
    ];

    function slotForBinding(b) {
        if (b.control && b.shift) return 'controlShiftKeys';
        if (b.control) return 'controlKeys';
        if (b.shift) return 'shiftKeys';
        return 'normalKeys';
    }

    // Snapshot draw.io's pre-existing bindings for each combo we intend to use.
    var priorBindings = {};
    MY_BINDINGS.forEach(function (b) {
        var slot = slotForBinding(b);
        var map = ui.keyHandler[slot];
        priorBindings[b.code + '|' + slot] = !!(map && typeof map[b.code] === 'function');
    });

    // Register all bindings from the single source of truth.
    MY_BINDINGS.forEach(function (b) {
        k.bindAction(b.code, b.shift, b.action, b.control);
    });

    // Report collisions (our binding overrides an existing draw.io binding).
    var conflictList = [];
    MY_BINDINGS.forEach(function (b) {
        var slot = slotForBinding(b);
        if (priorBindings[b.code + '|' + slot]) {
            conflictList.push(b.label + ' → ' + b.action);
        }
    });
    if (conflictList.length > 0) {
        console.warn('[Consultant Toolkit] These shortcuts override existing ' +
            'draw.io bindings (the built-in feature is shadowed):\n  ' +
            conflictList.join('\n  '));
    }
    ui._shortcutConflicts = conflictList;

    // Cmd+, direct listener (keyEvent may be swallowed before bindAction)
    document.addEventListener('keydown', function (e) {
        if ((e.metaKey || e.ctrlKey) && !e.shiftKey && e.key === ',') {
            e.preventDefault();
            var c = ui.actions.get('configuration...');
            if (c) { c.funct(); }
        }
        // Cmd+Shift+B → Insert Business Framework (fallback if bindAction fails)
        if ((e.metaKey || e.ctrlKey) && e.shiftKey && (e.key === 'B' || e.code === 'KeyB')) {
            e.preventDefault();
            var ibf = ui.actions.get('insertBusinessFramework');
            if (ibf) { ibf.funct(); }
        }
        // Cmd+Shift+N → new page (fallback if bindAction fails)
        if ((e.metaKey || e.ctrlKey) && e.shiftKey && (e.key === 'N' || e.code === 'KeyN')) {
            e.preventDefault();
            var np = ui.actions.get('insertPage');
            if (np) { np.funct(); }
        }
        // Cmd+Shift+. → cycle shape (fallback if bindAction fails)
        if ((e.metaKey || e.ctrlKey) && e.shiftKey && (e.key === '.' || e.code === 'Period')) {
            e.preventDefault();
            var cy = ui.actions.get('cycleShape');
            if (cy) { cy.funct(); }
        }
        // Cmd+Shift+N / Cmd+Opt+N → new page
        if ((e.metaKey || e.ctrlKey) && (e.shiftKey || e.altKey) && (e.key === 'N' || e.code === 'KeyN')) {
            e.preventDefault();
            var pg = ui.actions.get('insertPage');
            if (pg) { pg.funct(); }
        }
        // Cmd+Shift+I → insert icon
        if ((e.metaKey || e.ctrlKey) && e.shiftKey && (e.key === 'I' || e.code === 'KeyI')) {
            e.preventDefault();
            var ii = ui.actions.get('insertIcon');
            if (ii) { ii.funct(); }
        }
        // Cmd+Shift+? → shortcuts help
        if ((e.metaKey || e.ctrlKey) && e.shiftKey && (e.key === '?' || e.code === 'Slash')) {
            e.preventDefault();
            var hp = ui.actions.get('shortcutsHelp');
            if (hp) { hp.funct(); }
        }
        // Cmd+Shift+T → Draw.io's native template/new dialog
        if ((e.metaKey || e.ctrlKey) && e.shiftKey && e.key === 'T') {
            e.preventDefault();
            var t = ui.actions.get('insertTemplate') || ui.actions.get('templates') || ui.actions.get('template') || ui.actions.get('newDocument');
            if (t) { t.funct(); }
        }
        // Cmd+Shift+. → cycle shape (fallback if bindAction fails)
        if ((e.metaKey || e.ctrlKey) && e.shiftKey && (e.key === '.' || e.code === 'Period')) {
            e.preventDefault();
            var cy = ui.actions.get('cycleShape');
            if (cy) { cy.funct(); }
        }
        // Cmd+[ / Cmd+] → decrease / increase font size
        if ((e.metaKey || e.ctrlKey) && !e.shiftKey && (e.key === '[' || e.code === 'BracketLeft')) {
            e.preventDefault();
            var df = ui.actions.get('decreaseFont');
            if (df) { df.funct(); }
        }
        if ((e.metaKey || e.ctrlKey) && !e.shiftKey && (e.key === ']' || e.code === 'BracketRight')) {
            e.preventDefault();
            var inf = ui.actions.get('increaseFont');
            if (inf) { inf.funct(); }
        }
        // Cmd+9 → fill color picker
        if ((e.metaKey || e.ctrlKey) && !e.shiftKey && (e.key === '9' || e.code === 'Digit9')) {
            e.preventDefault();
            var fp = ui.actions.get('fillColorPicker');
            if (fp) { fp.funct(); }
        }
        // Cmd+0 → stroke color picker
        if ((e.metaKey || e.ctrlKey) && !e.shiftKey && (e.key === '0' || e.code === 'Digit0')) {
            e.preventDefault();
            var sp = ui.actions.get('strokeColorPicker');
            if (sp) { sp.funct(); }
        }
        // Cmd+Shift+/ (?) → shortcuts help
        if ((e.metaKey || e.ctrlKey) && e.shiftKey) {
            if (e.key === '?' || e.code === 'Slash') {
                e.preventDefault();
                var hp = ui.actions.get('shortcutsHelp');
                if (hp) { hp.funct(); }
            }
        }
        // Insert new page: try Cmd+Shift+N (best-effort) AND Cmd+Alt+N (reliable;
        // browsers reserve Cmd+Shift+N for a new incognito window and may swallow it)
        if ((e.metaKey || e.ctrlKey) && (e.key === 'n' || e.code === 'KeyN')) {
            if (e.shiftKey || e.altKey) {
                e.preventDefault();
                if (typeof ui.insertPage === 'function') { ui.insertPage(); }
                else { var pg = ui.actions.get('insertPage'); if (pg) { pg.funct(); } }
            }
        }
        // Cmd+` → generate Mermaid from selection
        if ((e.metaKey || e.ctrlKey) && !e.shiftKey && (e.key === '`' || e.code === 'Backquote')) {
            e.preventDefault();
            var gm = ui.actions.get('generateMermaid');
            if (gm) { gm.funct(); }
        }
        // Cmd+Shift+G → Force GTM Sequence
        if ((e.metaKey || e.ctrlKey) && e.shiftKey && (e.key === 'G' || e.code === 'KeyG')) {
            e.preventDefault();
            var fs = ui.actions.get('forceSequence');
            if (fs) { fs.funct(); }
        }
        // Cmd+Option (Alt) shortcuts for alignment / distribute / utilities
        if ((e.metaKey || e.ctrlKey) && e.altKey && !e.shiftKey) {
            var codeMap = {
                65: 'alignLeft', 67: 'alignCenter', 82: 'alignRight',
                84: 'alignTop', 77: 'alignMiddle', 66: 'alignBottom',
                68: 'distributeHorizontal', 86: 'distributeVertical',
                70: 'fitTextToShape', 71: 'routeEdgesSmart',
                90: 'zoomToSelection', 80: 'exportSelectionPNG'
            };
            var actName = codeMap[e.keyCode];
            if (actName) {
                e.preventDefault();
                var act = ui.actions.get(actName);
                if (act) { act.funct(); }
            }
        }
    }, { capture: true });

    // ─── BEAUTIFICATION & USER-FRIENDLY FEATURES ───

    // --- SMART ALIGNMENT GUIDES (visual snap lines) ---

    // --- SMART DISTRIBUTE / ALIGN ACTIONS ---
    ui.actions.addAction('alignLeft', function () {
        var cells = graph.getSelectionCells().filter(function (c) { return model.isVertex(c) && model.getGeometry(c); });
        if (cells.length < 2) return;
        var minX = Math.min.apply(null, cells.map(function (c) { return model.getGeometry(c).x; }));
        model.beginUpdate();
        try { cells.forEach(function (c) { var g = model.getGeometry(c); if (g) model.setGeometry(c, new mxGeometry(minX, g.y, g.width, g.height)); }); }
        finally { model.endUpdate(); }
    });
    ui.actions.addAction('alignCenter', function () {
        var cells = graph.getSelectionCells().filter(function (c) { return model.isVertex(c) && model.getGeometry(c); });
        if (cells.length < 2) return;
        var centers = cells.map(function (c) { var g = model.getGeometry(c); return g.x + g.width / 2; });
        var avg = centers.reduce(function (a, b) { return a + b; }, 0) / centers.length;
        model.beginUpdate();
        try { cells.forEach(function (c) { var g = model.getGeometry(c); if (g) model.setGeometry(c, new mxGeometry(avg - g.width / 2, g.y, g.width, g.height)); }); }
        finally { model.endUpdate(); }
    });
    ui.actions.addAction('alignRight', function () {
        var cells = graph.getSelectionCells().filter(function (c) { return model.isVertex(c) && model.getGeometry(c); });
        if (cells.length < 2) return;
        var maxRight = Math.max.apply(null, cells.map(function (c) { var g = model.getGeometry(c); return g.x + g.width; }));
        model.beginUpdate();
        try { cells.forEach(function (c) { var g = model.getGeometry(c); if (g) model.setGeometry(c, new mxGeometry(maxRight - g.width, g.y, g.width, g.height)); }); }
        finally { model.endUpdate(); }
    });
    ui.actions.addAction('alignTop', function () {
        var cells = graph.getSelectionCells().filter(function (c) { return model.isVertex(c) && model.getGeometry(c); });
        if (cells.length < 2) return;
        var minY = Math.min.apply(null, cells.map(function (c) { return model.getGeometry(c).y; }));
        model.beginUpdate();
        try { cells.forEach(function (c) { var g = model.getGeometry(c); if (g) model.setGeometry(c, new mxGeometry(g.x, minY, g.width, g.height)); }); }
        finally { model.endUpdate(); }
    });
    ui.actions.addAction('alignMiddle', function () {
        var cells = graph.getSelectionCells().filter(function (c) { return model.isVertex(c) && model.getGeometry(c); });
        if (cells.length < 2) return;
        var avg = cells.map(function (c) { var g = model.getGeometry(c); return g.y + g.height / 2; }).reduce(function (a, b) { return a + b; }, 0) / cells.length;
        model.beginUpdate();
        try { cells.forEach(function (c) { var g = model.getGeometry(c); if (g) model.setGeometry(c, new mxGeometry(g.x, avg - g.height / 2, g.width, g.height)); }); }
        finally { model.endUpdate(); }
    });
    ui.actions.addAction('alignBottom', function () {
        var cells = graph.getSelectionCells().filter(function (c) { return model.isVertex(c) && model.getGeometry(c); });
        if (cells.length < 2) return;
        var maxBottom = Math.max.apply(null, cells.map(function (c) { var g = model.getGeometry(c); return g.y + g.height; }));
        model.beginUpdate();
        try { cells.forEach(function (c) { var g = model.getGeometry(c); if (g) model.setGeometry(c, new mxGeometry(g.x, maxBottom - g.height, g.width, g.height)); }); }
        finally { model.endUpdate(); }
    });
    ui.actions.addAction('distributeHorizontal', function () {
        var cells = graph.getSelectionCells().filter(function (c) { return model.isVertex(c) && model.getGeometry(c); });
        if (cells.length < 3) return;
        cells.sort(function (a, b) { return model.getGeometry(a).x - model.getGeometry(b).x; });
        var first = model.getGeometry(cells[0]).x;
        var last = model.getGeometry(cells[cells.length - 1]).x + model.getGeometry(cells[cells.length - 1]).width;
        var totalW = cells.reduce(function (s, c) { return s + model.getGeometry(c).width; }, 0);
        var gap = (model.getGeometry(cells[cells.length - 1]).x - (model.getGeometry(cells[0]).x + model.getGeometry(cells[0]).width)) / (cells.length - 1);
        var x = model.getGeometry(cells[0]).x + model.getGeometry(cells[0]).width + gap;
        model.beginUpdate();
        try {
            for (var i = 1; i < cells.length - 1; i++) {
                var g = model.getGeometry(cells[i]);
                if (g) model.setGeometry(cells[i], new mxGeometry(x, g.y, g.width, g.height));
                x += model.getGeometry(cells[i]).width + gap;
            }
        } finally { model.endUpdate(); }
    });
    ui.actions.addAction('distributeVertical', function () {
        var cells = graph.getSelectionCells().filter(function (c) { return model.isVertex(c) && model.getGeometry(c); });
        if (cells.length < 3) return;
        cells.sort(function (a, b) { return model.getGeometry(a).y - model.getGeometry(b).y; });
        var first = model.getGeometry(cells[0]).y;
        var last = model.getGeometry(cells[cells.length - 1]).y + model.getGeometry(cells[cells.length - 1]).height;
        var gap = (model.getGeometry(cells[cells.length - 1]).y - (model.getGeometry(cells[0]).y + model.getGeometry(cells[0]).height)) / (cells.length - 1);
        var y = model.getGeometry(cells[0]).y + model.getGeometry(cells[0]).height + gap;
        model.beginUpdate();
        try {
            for (var i = 1; i < cells.length - 1; i++) {
                var g = model.getGeometry(cells[i]);
                if (g) model.setGeometry(cells[i], new mxGeometry(g.x, y, g.width, g.height));
                y += model.getGeometry(cells[i]).height + gap;
            }
        } finally { model.endUpdate(); }
    });
    ui.actions.addAction('fitTextToShape', function () {
        var cells = graph.getSelectionCells().filter(function (c) { return model.isVertex(c); });
        model.beginUpdate();
        try {
            cells.forEach(function (cell) {
                var g = model.getGeometry(cell);
                if (!g) return;
                var style = graph.getCellStyle(cell);
                var curSize = parseInt(mxUtils.getValue(graph.getCellStyle(cell), 'fontSize', '12'), 10);
                var text = cell.value || '';
                var lines = text.split('\n').length;
                var lineH = curSize * 1.5;
                var neededH = lines * lineH + 16;
                var availH = model.getGeometry(cell).height;
                if (neededH > model.getGeometry(cell).height && curSize > 8) {
                    var newSize = Math.max(8, Math.floor(curSize * (model.getGeometry(cell).height / (lines * curSize * 1.5 + 16))));
                    graph.setCellStyles('fontSize', newSize, [cell]);
                }
            });
        } finally { model.endUpdate(); }
    });
    ui.actions.addAction('routeEdgesSmart', function () {
        var cells = graph.getSelectionCells().filter(function (c) { return model.isEdge(c); });
        cells.forEach(function (edge) {
            var source = graph.getModel().getTerminal(edge, true);
            var target = graph.getModel().getTerminal(edge, false);
            if (!source || !target) return;
            var sGeo = model.getGeometry(source);
            var tGeo = model.getGeometry(target);
            if (!sGeo || !tGeo) return;
            var sCenterX = sGeo.x + sGeo.width / 2;
            var sCenterY = sGeo.y + sGeo.height / 2;
            var tCenterX = tGeo.x + tGeo.width / 2;
            var tCenterY = tGeo.y + tGeo.height / 2;
            var dx = tCenterX - sCenterX;
            var dy = tCenterY - sCenterY;
            var isHorizontal = Math.abs(dx) > Math.abs(dy);
            var style = model.getStyle(edge) || '';
            if (isHorizontal) {
                style = style.replace(/exitX=[^;]*;?/g, '').replace(/entryX=[^;]*;?/g, '');
                style += 'exitX=' + (dx > 0 ? 1 : 0) + ';exitY=0.5;entryX=' + (dx > 0 ? 0 : 1) + ';entryY=0.5;';
            } else {
                style = style.replace(/exitY=[^;]*;?/g, '').replace(/entryY=[^;]*;?/g, '');
                style += 'exitX=0.5;exitY=' + (dy > 0 ? 1 : 0) + ';entryX=0.5;entryY=' + (dy > 0 ? 0 : 1) + ';';
            }
            model.setStyle(edge, style);
        });
    });

    // --- ZOOM TO SELECTION (Cmd+Shift+Z) ---
    ui.actions.addAction('zoomToSelection', function () {
        var cells = graph.getSelectionCells().filter(function (c) { return model.isVertex(c); });
        if (cells.length === 0) return;
        var bounds = null;
        cells.forEach(function (c) {
            var g = model.getGeometry(c);
            if (g) { if (!bounds) bounds = g.clone(); else bounds.add(g); }
        });
        if (bounds) {
            var scale = Math.min(1.5, Math.min(800 / bounds.width, 600 / bounds.height));
            graph.view.scaleAndTranslate(scale, (graph.container.clientWidth / 2 - (bounds.x + bounds.width / 2) * scale) / scale, (graph.container.clientHeight / 2 - (bounds.y + bounds.height / 2) * scale) / scale);
        }
    });

    // --- EXPORT SELECTION AS PNG ---
    ui.actions.addAction('exportSelectionPNG', function () {
        var cells = graph.getSelectionCells().filter(function (c) { return model.isVertex(c); });
        if (cells.length === 0) return;
        var bounds = null;
        cells.forEach(function (c) {
            var g = model.getGeometry(c);
            if (g) { if (!bounds) bounds = g.clone(); else bounds.add(g); }
        });
        if (!bounds) return;
        var scale = 2;
        var canvas = document.createElement('canvas');
        canvas.width = bounds.width * scale + 40;
        canvas.height = bounds.height * scale + 40;
        var ctx = canvas.getContext('2d');
        ctx.scale(scale, scale);
        ctx.translate(-bounds.x + 20, -bounds.y + 20);
        var img = graph.getImageExport(canvas, bounds, scale, '#FFFFFF', false);
        if (img) {
            var link = document.createElement('a');
            link.download = 'framework-' + Date.now() + '.png';
            link.href = img;
            link.click();
        }
    });

