                    py: 'def valid_parens(s):\n    stack = []\n    mapping = {")":"(", "]":"[", "}":"{"}\n    for char in s:\n        if char in mapping:\n            top = stack.pop() if stack else "#"\n            if mapping[char] != top: return False\n        else:\n            stack.append(char)\n    return not stack\n\n# Monotonic Stack\ndef next_greater(arr):\n    stack, result = [], [-1]*len(arr)\n    for i in range(len(arr)):\n        while stack and arr[i] > arr[stack[-1]]:\n            result[stack.pop()] = arr[i]\n        stack.append(i)\n    return result',
