                'Parentheses Gen': { d:'Low', l:'Add ( if open<n, add ) if close<open', e:'Valid parentheses combinations' },
                'Word Search Grid': { d:'Med', l:'DFS from each cell; mark, explore 4 dirs, unmark', e:'Word path in matrix, Boggle' },
                'N-Queens': { d:'High', l:'Row-by-row; check cols, diags for conflicts', e:'Constraint satisfaction, Sudoku' },
